#include <iostream>
using namespace std;
int w,n,a[30001];
int main(){
    cin>>w>>n;
    for(int i=1;i<=n;i++)cin>>a[i];
    int left=1,right=n,sum=0;
    for(int i=1;i<n;i++)
        for(int j=i+1;j<=n;j++)
            if(a[i]>a[j])swap(a[i],a[j]);
    while(left<=right){
        sum++;
        if(left==right)
            break;
        else{
            if(a[left]+a[right]<=w){
                left++;
                right--;
            }
            else{
                right--;
            }
        }
    }
    cout<<sum;
    return 0;
}
